// ─── AttentionCard ─────────────────────────────────────────────────────────
function AttentionCard({plant, careLog, onLog, onSelect}){
  const T = React.useContext(ThemeCtx);
  const photo = getCustomPhoto(plant.id)||(plant.type==='indoor'
    ? (INDOOR_PHOTOS[plant.id]||STATIC_PHOTO_URLS[plant.id])
    : STATIC_PHOTO_URLS[plant.id]);
  const wU = getUrgency(plant,careLog,'watered');
  const fU = getUrgency(plant,careLog,'fed');
  const rU = repotApplicable(plant)?getUrgency(plant,careLog,'repotted'):null;
  const needs = [
    wU.level==='overdue'&&{type:'watered',label:'Water',icon:'&#x1F4A7;',color:'#3b82f6'},
    fU.level==='overdue'&&{type:'fed',    label:'Feed', icon:'&#x1F9EA;',color:'#10b981'},
    rU&&rU.level==='overdue'&&{type:'repotted',label:'Repot',icon:'&#x1FAB4;',color:'#a855f7'},
  ].filter(Boolean);
  if(!needs.length)return null;
  return (
    <div style={{display:'flex',alignItems:'center',gap:12,padding:'10px 14px',
      background:T.card,borderRadius:10,border:'1px solid rgba(239,68,68,0.3)',
      borderLeft:'3px solid #ef4444'}}>
      <div style={{width:44,height:44,borderRadius:8,overflow:'hidden',background:T.surface,flexShrink:0}}>
        {photo&&<img src={photo} alt={plant.name} style={{width:'100%',height:'100%',objectFit:'cover'}}/>}
      </div>
      <div style={{flex:1,minWidth:0}}>
        <div style={{fontWeight:600,fontSize:13,color:T.text,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{plant.name}</div>
        <div style={{fontSize:11,color:T.sub}}>{plant.latin}</div>
      </div>
      <div style={{display:'flex',gap:6,flexShrink:0}}>
        {needs.map(n=>(
          <button key={n.type} onClick={()=>onLog(plant.id,n.type)} style={{
            padding:'4px 10px',background:n.color,border:'none',borderRadius:6,
            color:'#fff',fontSize:12,cursor:'pointer',fontWeight:600,display:'flex',gap:4,alignItems:'center'}}>
            <span dangerouslySetInnerHTML={{__html:n.icon}}/>{n.label}
          </button>
        ))}
        <button onClick={()=>onSelect(plant)} style={{padding:'4px 8px',background:T.input,
          border:'1px solid '+T.border,borderRadius:6,color:T.sub,fontSize:12,cursor:'pointer'}}>
          &#x2192;
        </button>
      </div>
    </div>
  );
}

// ─── CareStreak ────────────────────────────────────────────────────────────
function CareStreak({careLog, allPlants}){
  const T = React.useContext(ThemeCtx);
  const now = Date.now();
  const week = 7*86400000, fortnight=14*86400000;
  const watered  = allPlants.filter(p=>careLog[String(p.id)+'-watered']&&(now-careLog[String(p.id)+'-watered'])<week).length;
  const fed      = allPlants.filter(p=>careLog[String(p.id)+'-fed']    &&(now-careLog[String(p.id)+'-fed'])<fortnight).length;
  const overdue  = allPlants.filter(p=>getUrgency(p,careLog,'watered').level==='overdue').length;
  const total = allPlants.length;
  const pct = Math.round(watered/total*100);
  const stats = [
    {val:watered, of:total, label:'watered this week',   color:'#3b82f6', icon:'&#x1F4A7;'},
    {val:fed,     of:total, label:'fed this fortnight',  color:'#10b981', icon:'&#x1F9EA;'},
    {val:overdue, of:total, label:'need water now',      color:'#ef4444', icon:'&#x26A0;'},
  ];
  return (
    <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))',gap:12,marginBottom:24}}>
      {stats.map((s,i)=>(
        <div key={i} style={{background:T.card,border:'1px solid '+T.border,borderRadius:12,padding:'14px 16px'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:8}}>
            <span style={{fontSize:22}} dangerouslySetInnerHTML={{__html:s.icon}}/>
            <span style={{fontSize:26,fontWeight:700,color:s.color}}>{s.val}</span>
          </div>
          <div style={{fontSize:12,color:T.sub}}>{s.label}</div>
          <div style={{marginTop:8,height:4,background:T.surface,borderRadius:2,overflow:'hidden'}}>
            <div style={{height:'100%',background:s.color,width:(s.val/s.of*100)+'%',borderRadius:2,transition:'width 0.5s'}}/>
          </div>
        </div>
      ))}
    </div>
  );
}

// ─── SowingCalendar ────────────────────────────────────────────────────────
