// ─── Background image helper — resizes dropped/selected photo before storing ─
function resizeImageToDataURL(file,maxW=1400,quality=0.68){
  return new Promise(resolve=>{
    const img=new Image(),url=URL.createObjectURL(file);
    img.onload=()=>{
      URL.revokeObjectURL(url);
      const scale=Math.min(1,maxW/img.width);
      const c=document.createElement('canvas');
      c.width=Math.round(img.width*scale);
      c.height=Math.round(img.height*scale);
      c.getContext('2d').drawImage(img,0,0,c.width,c.height);
      resolve(c.toDataURL('image/jpeg',quality));
    };
    img.src=url;
  });
}

// ─── MapGrid — cell-keyed model supports placing same plant in multiple zones ─
// Storage: pos = { "x,y": plantId }  (cell owns the plant, not the other way)
function MapGrid({storageKey,cols,rows,size,zones,defaultFilter,defaultPos,defaultText,allPlants,careLog,onSelect,fullHeight=false}){
  const T=React.useContext(ThemeCtx);
  const [pos,setPos]=React.useState(()=>{
    try{
      const s=JSON.parse(localStorage.getItem(storageKey)||'null');
      // Migrate old format {plantId:{x,y}} → new format {"x,y":plantId}
      if(s && typeof s === 'object'){
        const first = Object.values(s)[0];
        if(first && typeof first === 'object' && 'x' in first){
          const migrated={};
          Object.entries(s).forEach(([id,v])=>{ migrated[`${v.x},${v.y}`]=id; });
          return migrated;
        }
        return s;
      }
      return defaultPos||{};
    }catch{return defaultPos||{};}
  });
  const [dragId,setDragId]=React.useState(null);
  const clickTimerRef=React.useRef(null);
  const [hov,setHov]=React.useState(null);
  const [zFilter,setZFilter]=React.useState(defaultFilter||'all');
  const [showPlantPicker,setShowPlantPicker]=React.useState(false);
  const [pickerFilter,setPickerFilter]=React.useState(defaultFilter||'all');
  const [pickerSearch,setPickerSearch]=React.useState('');
  const [bgImage,setBgImage]=React.useState(()=>{try{return localStorage.getItem(storageKey+'-bg')||null;}catch{return null;}});
  const [bgDragOver,setBgDragOver]=React.useState(false);
  // Paint state
  const [cellColor,setCellColor]=React.useState(()=>{try{return JSON.parse(localStorage.getItem(storageKey+'-color')||'{}');}catch{return {};}});
  const [cellText,setCellText]=React.useState(()=>{try{const s=JSON.parse(localStorage.getItem(storageKey+'-text')||'null');return s||defaultText||{};}catch{return defaultText||{};}});
  const [mode,setMode]=React.useState('place'); // 'place' | 'label' | 'paint' | 'shape'
  const [paintColor,setPaintColor]=React.useState('#86efac');
  const [isPainting,setIsPainting]=React.useState(false);
  const [editCell,setEditCell]=React.useState(null);
  const [editText,setEditText]=React.useState('');
  const [disabledCells,setDisabledCells]=React.useState(()=>{
    try{return new Set(JSON.parse(localStorage.getItem(storageKey+'-disabled')||'[]'));}
    catch{return new Set();}
  });
  const [shapeErasing,setShapeErasing]=React.useState(false);

  // ── Zone add/remove state ──────────────────────────────────────────────────
  const [customZones,setCustomZones]=React.useState(()=>{
    try{return JSON.parse(localStorage.getItem(storageKey+'-czones')||'[]');}catch{return [];}
  });
  const [removedZoneIds,setRemovedZoneIds]=React.useState(()=>{
    try{return new Set(JSON.parse(localStorage.getItem(storageKey+'-rzones')||'[]'));}catch{return new Set();}
  });
  const [zoneLabels,setZoneLabels]=React.useState(()=>{
    try{return JSON.parse(localStorage.getItem(storageKey+'-zlabels')||'{}');}catch{return {};}
  });
  // Zone drawing
  const [zoneDrawStart,setZoneDrawStart]=React.useState(null);
  const [zoneDrawEnd,setZoneDrawEnd]=React.useState(null);
  const [pendingZoneRect,setPendingZoneRect]=React.useState(null); // {x,y,w,h}
  const [newZoneLabel,setNewZoneLabel]=React.useState('');
  const [newZoneColorIdx,setNewZoneColorIdx]=React.useState(0);
  const [editingZoneId,setEditingZoneId]=React.useState(null);
  const [editingZoneLabelVal,setEditingZoneLabelVal]=React.useState('');

  const ZONE_COLORS=[
    {col:'rgba(59,130,246,0.13)',border:'#3b82f6'},
    {col:'rgba(16,185,129,0.15)',border:'#10b981'},
    {col:'rgba(139,92,246,0.13)',border:'#8b5cf6'},
    {col:'rgba(234,179,8,0.13)' ,border:'#eab308'},
    {col:'rgba(239,68,68,0.13)' ,border:'#ef4444'},
    {col:'rgba(249,115,22,0.13)',border:'#f97316'},
    {col:'rgba(236,72,153,0.13)',border:'#ec4899'},
    {col:'rgba(107,114,128,0.15)',border:'#6b7280'},
    {col:'rgba(161,107,59,0.18)',border:'#a16b3b'},
    {col:'rgba(20,184,166,0.13)',border:'#14b8a6'},
  ];

  const PALETTE=['#86efac','#166534','#bef264','#fde68a','#fda4af','#93c5fd','#c4b5fd','#9ca3af','#92400e','#f97316','#ef4444','#ffffff'];
  const LIGHT_LEVELS=[{c:'#fef9c3',l:'Full Sun',i:'☀️'},{c:'#fef3c7',l:'Partial Sun',i:'🌤'},{c:'#dbeafe',l:'Indirect Light',i:'🌥'},{c:'#e5e7eb',l:'Low Light',i:'🌑'}];

  function saveBg(dataUrl){
    setBgImage(dataUrl);
    try{if(dataUrl)localStorage.setItem(storageKey+'-bg',dataUrl);else localStorage.removeItem(storageKey+'-bg');}catch{}
  }
  async function handleBgFile(file){
    if(!file||!file.type.startsWith('image/'))return;
    const dataUrl=await resizeImageToDataURL(file);
    saveBg(dataUrl);
  }
  function saveCellColor(key,color){
    const n={...cellColor};
    if(color)n[key]=color; else delete n[key];
    setCellColor(n);
    try{localStorage.setItem(storageKey+'-color',JSON.stringify(n));}catch{}
  }
  function saveCellText(key,text){
    const n={...cellText};
    if(text.trim())n[key]=text.trim(); else delete n[key];
    setCellText(n);
    try{localStorage.setItem(storageKey+'-text',JSON.stringify(n));}catch{}
    setEditCell(null);
  }
  function doPaint(key){
    saveCellColor(key, cellColor[key]===paintColor?null:paintColor);
  }
  function doShape(key,erase){
    const next=new Set(disabledCells);
    if(erase)next.delete(key); else next.add(key);
    setDisabledCells(next);
    try{localStorage.setItem(storageKey+'-disabled',JSON.stringify([...next]));}catch{}
  }
  function resetShape(){
    setDisabledCells(new Set());
    try{localStorage.removeItem(storageKey+'-disabled');}catch{}
  }

  // Zone position overrides — stores {x,y} top-left per zone id, persisted
  const [zonePositions,setZonePositions]=React.useState(()=>{
    try{return JSON.parse(localStorage.getItem(storageKey+'-zpos')||'{}');}
    catch{return {};}
  });
  function getZonePos(z){return zonePositions[z.id]||{x:z.x,y:z.y};}

  // All live zones = preset (minus removed, with label overrides) + custom (minus removed)
  const effectiveZones=[
    ...(zones||[]).filter(z=>!removedZoneIds.has(z.id)).map(z=>({...z,label:zoneLabels[z.id]||z.label})),
    ...customZones.filter(z=>!removedZoneIds.has(z.id)).map(z=>({...z,label:zoneLabels[z.id]||z.label})),
  ];

  function moveZone(zid,dropX,dropY){
    const z=effectiveZones.find(q=>q.id===zid);
    if(!z)return;
    const nx=Math.max(0,Math.min(dropX,cols-z.w));
    const ny=Math.max(0,Math.min(dropY,rows-z.h));
    const next={...zonePositions,[zid]:{x:nx,y:ny}};
    setZonePositions(next);
    try{localStorage.setItem(storageKey+'-zpos',JSON.stringify(next));}catch{}
  }
  function resetZones(){
    setZonePositions({});
    try{localStorage.removeItem(storageKey+'-zpos');}catch{}
  }
  function removeZone(zid){
    const next=new Set(removedZoneIds); next.add(zid);
    setRemovedZoneIds(next);
    try{localStorage.setItem(storageKey+'-rzones',JSON.stringify([...next]));}catch{}
  }
  function addZone(rect,label,colorIdx){
    const c=ZONE_COLORS[colorIdx]||ZONE_COLORS[0];
    const z={id:'cz-'+Date.now(),label:label||'New zone',
      col:c.col,border:c.border,x:rect.x,y:rect.y,w:rect.w,h:rect.h};
    const next=[...customZones,z];
    setCustomZones(next);
    try{localStorage.setItem(storageKey+'-czones',JSON.stringify(next));}catch{}
  }
  function saveZoneLabel(zid,val){
    const next={...zoneLabels,[zid]:val.trim()};
    setZoneLabels(next);
    try{localStorage.setItem(storageKey+'-zlabels',JSON.stringify(next));}catch{}
    setEditingZoneId(null);
  }
  function confirmNewZone(){
    if(!pendingZoneRect)return;
    addZone(pendingZoneRect,newZoneLabel,newZoneColorIdx);
    setPendingZoneRect(null);setNewZoneLabel('');setNewZoneColorIdx(0);
  }

  function save(p){setPos(p);try{localStorage.setItem(storageKey,JSON.stringify(p));}catch{}}
  // Cells hold a comma-separated list of plant ids, e.g. "33,60" — a mixed pot with two species.
  // Single-plant cells are just one id with no comma (backward compatible with older saved layouts).
  function placeAt(pid,x,y,fromCell=null){
    const key=`${x},${y}`;
    const pidStr=String(pid);
    const existing=(pos[key]||'').split(',').filter(Boolean);
    const list=existing.includes(pidStr)?existing:[...existing,pidStr];
    const next={...pos,[key]:list.join(',')};
    if(fromCell&&fromCell!==key){
      const fromList=(pos[fromCell]||'').split(',').filter(Boolean).filter(id=>id!==pidStr);
      if(fromList.length) next[fromCell]=fromList.join(',');
      else delete next[fromCell];
    }
    save(next);
  }
  function removeCell(x,y,pid=null){
    const key=`${x},${y}`;
    if(pid==null){ const n={...pos}; delete n[key]; save(n); return; }
    const list=(pos[key]||'').split(',').filter(Boolean).filter(id=>id!==String(pid));
    const n={...pos};
    if(list.length) n[key]=list.join(','); else delete n[key];
    save(n);
  }

  function exportLayout(){
    const zonesOut=effectiveZones.map(z=>{const zp=getZonePos(z);return {id:z.id,label:z.label,x:zp.x,y:zp.y,w:z.w,h:z.h};});
    const plantsOut=Object.entries(pos).flatMap(([key,val])=>{
      const [x,y]=key.split(',').map(Number);
      return String(val).split(',').filter(Boolean).map(pid=>{
        const p=allPlants.find(q=>String(q.id)===pid);
        return {x,y,plantId:pid,name:p?p.name:pid};
      });
    }).sort((a,b)=>a.y-b.y||a.x-b.x);
    const labelsOut=Object.entries(cellText).map(([key,text])=>{
      const [x,y]=key.split(',').map(Number);
      return {x,y,text};
    });
    const json=JSON.stringify({map:storageKey,zones:zonesOut,plants:plantsOut,labels:labelsOut},null,2);
    if(navigator.clipboard&&navigator.clipboard.writeText){
      navigator.clipboard.writeText(json).then(
        ()=>window.alert('Layout copied to clipboard — paste it into your chat with Claude to make this the permanent default.'),
        ()=>window.prompt('Copy this layout JSON and paste it into your chat with Claude:',json)
      );
    }else{
      window.prompt('Copy this layout JSON and paste it into your chat with Claude:',json);
    }
  }

  // Build cellMap: "x,y" → array of plant objects (usually length 1; 2+ for a shared/mixed pot)
  const cellMap={};
  Object.entries(pos).forEach(([key,val])=>{
    const ids=String(val).split(',').filter(Boolean);
    const plants=ids.map(id=>allPlants.find(q=>String(q.id)===id)).filter(Boolean);
    if(plants.length) cellMap[key]=plants;
  });
  const TC={outdoor:'#4a7c3f',indoor:'#1e40af',hydro:'#d97706'};
  function photo(p){return getCustomPhoto(p.id)||(plantCategory(p)==='indoor'?(INDOOR_PHOTOS[p.id]||STATIC_PHOTO_URLS[p.id]||null):STATIC_PHOTO_URLS[p.id]||null);}
  function getZn(x,y){
    return effectiveZones.find(z=>{const p=getZonePos(z);return x>=p.x&&x<p.x+z.w&&y>=p.y&&y<p.y+z.h;})||null;
  }

  // Sidebar: always shows all plants — same plant can be placed in multiple cells
  const sidebar=allPlants.filter(p=>zFilter==='all'||plantCategory(p)===zFilter);
  const countInMap=pid=>Object.values(pos).filter(v=>String(v).split(',').includes(String(pid))).length;
  const GP=4, gridW=cols*(size+GP)-GP, gridH=rows*(size+GP)-GP;

  return (
    <>
    <div style={{display:'flex',gap:12,height:fullHeight?'calc(100vh - 96px)':'calc(100vh - 290px)',minHeight:500}}>
      {/* Sidebar */}
      <div style={{width:168,flexShrink:0,display:'flex',flexDirection:'column',background:T.card,borderRadius:12,border:'1px solid '+T.border,overflow:'hidden'}}>
        <div style={{padding:'10px 8px',borderBottom:'1px solid '+T.border}}>
          <div style={{fontSize:11,color:T.sub,fontWeight:600,textTransform:'uppercase',letterSpacing:.5,marginBottom:6}}>Filter</div>
          <div style={{display:'flex',flexWrap:'wrap',gap:3}}>
            {[['all','All'],['outdoor','Out'],['indoor','In'],['hydro','Glass']].map(([k,l])=>(
              <button key={k} onClick={()=>setZFilter(k)} style={{
                padding:'3px 7px',borderRadius:20,border:'1px solid '+T.border,cursor:'pointer',fontSize:10,
                background:zFilter===k?T.green:T.input,color:zFilter===k?'#fff':T.text}}>{l}
              </button>
            ))}
          </div>
        </div>
        <div style={{flex:1,overflowY:'auto',padding:8}}>
          <div style={{fontSize:11,color:T.sub,fontWeight:600,textTransform:'uppercase',letterSpacing:.5,marginBottom:6}}>
            Plants ({sidebar.length})
          </div>
          <div style={{fontSize:10,color:T.sub,marginBottom:8,lineHeight:1.4}}>Drag to place — same plant can go in multiple zones</div>
          {sidebar.map(p=>{
            const ph=photo(p),col=TC[plantCategory(p)];
            const cnt=countInMap(p.id);
            return(
              <div key={p.id} draggable
                onDragStart={e=>{e.dataTransfer.setData('plantId',String(p.id));setDragId(String(p.id));}}
                onDragEnd={()=>setDragId(null)}
                style={{display:'flex',gap:7,alignItems:'center',padding:'5px 6px',borderRadius:7,marginBottom:3,
                  cursor:'grab',userSelect:'none',background:dragId===String(p.id)?T.surface:T.input,
                  border:'1px solid '+T.border,borderLeft:'3px solid '+col,opacity:dragId===String(p.id)?.5:1}}>
                <div style={{width:28,height:28,borderRadius:5,overflow:'hidden',flexShrink:0,background:T.surface}}>
                  {ph&&<img src={ph} alt={p.name} style={{width:'100%',height:'100%',objectFit:'cover'}}/>}
                </div>
                <div style={{fontSize:11,fontWeight:600,color:T.text,lineHeight:1.2,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap',flex:1}}>{p.name}</div>
                {cnt>0&&<div style={{background:T.green,color:'#fff',borderRadius:'50%',width:16,height:16,fontSize:9,flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',fontWeight:700}}>{cnt}</div>}
              </div>
            );
          })}
          {!sidebar.length&&<div style={{textAlign:'center',color:T.sub,fontSize:11,padding:'20px 4px'}}>No plants match filter</div>}
        </div>
        <div style={{padding:'8px',borderTop:'1px solid '+T.border,maxHeight:220,overflowY:'auto'}}>
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
            <div style={{fontSize:10,color:T.sub,fontWeight:600,textTransform:'uppercase',letterSpacing:.5}}>
              Zones ({effectiveZones.length})
            </div>
            <button onClick={()=>setMode('zones')} title="Draw a new zone on the grid"
              style={{padding:'2px 7px',borderRadius:20,border:'1px solid '+T.border,cursor:'pointer',
                fontSize:11,background:mode==='zones'?T.accent:T.input,
                color:mode==='zones'?'#fff':T.sub,fontWeight:700,lineHeight:1.4}}>
              ＋
            </button>
          </div>
          {effectiveZones.length===0&&(
            <div style={{fontSize:10,color:T.sub,textAlign:'center',padding:'8px 0',lineHeight:1.4}}>
              No zones yet.<br/>Click ＋ then draw on the grid.
            </div>
          )}
          {effectiveZones.map(z=>(
            <div key={z.id} style={{display:'flex',alignItems:'center',gap:4,marginBottom:5}}>
              <div style={{width:10,height:10,borderRadius:2,flexShrink:0,
                background:z.col,border:'1px solid '+z.border}}/>
              {editingZoneId===z.id?(
                <input autoFocus value={editingZoneLabelVal}
                  onChange={e=>setEditingZoneLabelVal(e.target.value)}
                  onKeyDown={e=>{
                    if(e.key==='Enter')saveZoneLabel(z.id,editingZoneLabelVal);
                    if(e.key==='Escape')setEditingZoneId(null);
                  }}
                  onBlur={()=>saveZoneLabel(z.id,editingZoneLabelVal)}
                  style={{flex:1,padding:'2px 5px',borderRadius:4,border:'1px solid '+T.accent,
                    background:T.input,color:T.text,fontSize:10,outline:'none',minWidth:0}}/>
              ):(
                <span onClick={()=>{setEditingZoneId(z.id);setEditingZoneLabelVal(z.label);}}
                  title="Click to rename"
                  style={{fontSize:10,color:T.sub,lineHeight:1.2,flex:1,cursor:'text',
                    overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                  {z.label}
                </span>
              )}
              <button onClick={()=>{setEditingZoneId(z.id);setEditingZoneLabelVal(z.label);}}
                title="Rename zone"
                style={{padding:'1px 3px',border:'none',background:'transparent',
                  color:T.sub,cursor:'pointer',fontSize:10,flexShrink:0,lineHeight:1}}>
                &#x270F;
              </button>
              <button onClick={()=>removeZone(z.id)} title="Remove zone"
                style={{padding:'1px 4px',border:'none',background:'transparent',
                  color:'rgba(239,68,68,0.7)',cursor:'pointer',fontSize:11,lineHeight:1,
                  flexShrink:0,fontWeight:700}}>
                &#x2715;
              </button>
            </div>
          ))}
          {mode==='zones'&&(
            <div style={{fontSize:9,color:T.accent,marginTop:4,lineHeight:1.4}}>
              &#x2195; Drag on grid to draw zone
            </div>
          )}
        </div>
      </div>
      {/* Grid */}
      <div style={{flex:1,display:'flex',flexDirection:'column',gap:8,minWidth:0}}>
        {/* Mode toolbar */}
        <div style={{display:'flex',alignItems:'center',gap:6,flexWrap:'wrap'}}>
          {[['place','&#x1F33F; Place','Drag plants onto cells; drag placed plants to move them'],
            ['label','&#x270F;&#xFE0F; Label','Click any cell to add or edit a text label'],
            ['paint','&#x1F3A8; Paint','Click or drag across cells to colour them'],
            ['shape','&#x1F4D0; Shape','Click or drag cells to hide/show them — carve any shape from the grid'],
            ['zones','&#x1F5FA;&#xFE0F; Zones','Add new zones by dragging a rectangle; rename or delete existing zones']
          ].map(([m,lbl,tip])=>(
            <button key={m} title={tip} onClick={()=>{setMode(m);setEditCell(null);}}
              style={{padding:'4px 12px',borderRadius:20,border:'1px solid '+T.border,cursor:'pointer',fontSize:12,
                background:mode===m?T.accent:T.input,color:mode===m?'#fff':T.text,fontWeight:mode===m?700:400}}>
              <span dangerouslySetInnerHTML={{__html:lbl}}/>
            </button>
          ))}
          {mode==='paint'&&(
            <div style={{display:'flex',alignItems:'center',gap:4,marginLeft:6,flexWrap:'wrap'}}>
              {PALETTE.map(c=>(
                <div key={c} onClick={()=>setPaintColor(c)}
                  title={c}
                  style={{width:20,height:20,borderRadius:4,background:c,cursor:'pointer',flexShrink:0,
                    border:paintColor===c?'3px solid '+T.text:'2px solid rgba(0,0,0,0.25)',
                    boxSizing:'border-box',outline:paintColor===c?'1px solid '+T.accent:'none',outlineOffset:1}}/>
              ))}
              <div onClick={()=>setPaintColor('__erase__')} title="Eraser"
                style={{width:20,height:20,borderRadius:4,cursor:'pointer',flexShrink:0,display:'flex',
                  alignItems:'center',justifyContent:'center',fontSize:12,
                  border:paintColor==='__erase__'?'3px solid '+T.text:'2px solid rgba(0,0,0,0.25)',
                  background:T.surface,boxSizing:'border-box'}}>
                &#x2715;
              </div>
              <span style={{fontSize:10,color:T.sub,margin:'0 4px'}}>|</span>
              {LIGHT_LEVELS.map(({c,l,i})=>(
                <div key={c} onClick={()=>setPaintColor(c)} title={l}
                  style={{width:28,height:20,borderRadius:4,background:c,cursor:'pointer',flexShrink:0,
                    border:paintColor===c?'3px solid '+T.text:'2px solid rgba(0,0,0,0.25)',
                    boxSizing:'border-box',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11}}>
                  {i}
                </div>
              ))}
              <span style={{fontSize:10,color:T.sub,marginLeft:2}}>Light levels</span>
            </div>
          )}
          {mode==='shape'&&(
            <div style={{display:'flex',alignItems:'center',gap:8,marginLeft:6,flexWrap:'wrap'}}>
              <span style={{fontSize:11,color:T.sub}}>Click/drag cells to hide &bull; click faint ✕ cells to restore</span>
              <button onClick={resetShape} style={{
                padding:'3px 10px',borderRadius:20,border:'1px solid '+T.border,cursor:'pointer',fontSize:11,
                background:T.input,color:T.text}}>
                &#x21BA; Reset cells
              </button>
              {zones&&zones.length>0&&<button onClick={resetZones} style={{
                padding:'3px 10px',borderRadius:20,border:'1px solid '+T.border,cursor:'pointer',fontSize:11,
                background:T.input,color:T.text}}>
                &#x21BA; Reset zones
              </button>}
            </div>
          )}
          {mode==='place'&&effectiveZones.length>0&&(
            <span style={{fontSize:11,color:T.sub,marginLeft:6}}>&#x1F4CD; Drag zone labels to reposition</span>
          )}
          {mode==='zones'&&(
            <span style={{fontSize:11,color:T.sub,marginLeft:6}}>
              Drag to draw a new zone &bull; click zone label to rename &bull; &#x2715; to delete
            </span>
          )}
          <button onClick={()=>setShowPlantPicker(p=>!p)} title="Toggle plant picker panel"
            style={{padding:'4px 12px',borderRadius:20,border:'1px solid '+(showPlantPicker?T.accent:T.border),
              cursor:'pointer',fontSize:12,marginLeft:6,
              background:showPlantPicker?'rgba(74,124,63,0.15)':T.input,
              color:showPlantPicker?T.accent:T.text,fontWeight:showPlantPicker?700:400}}>
            &#x1F33F; Plants &#x25BE;
          </button>
          <div style={{marginLeft:'auto',display:'flex',gap:6,alignItems:'center'}}>
            <button onClick={exportLayout} title="Copy the current zones, plant placements and labels as JSON — paste it into your chat with Claude to make this the permanent default"
              style={{padding:'4px 10px',borderRadius:20,border:'1px solid '+T.border,
                background:T.input,color:T.text,cursor:'pointer',fontSize:11,fontWeight:600,
                display:'flex',alignItems:'center',gap:4}}>
              &#x1F4CB; Export Layout
            </button>
            {bgImage
              ? <button onClick={()=>saveBg(null)} style={{
                  padding:'4px 10px',borderRadius:20,border:'1px solid #ef4444',
                  background:'rgba(239,68,68,0.1)',color:'#ef4444',cursor:'pointer',fontSize:11,fontWeight:600}}>
                  &#x2715; Clear photo
                </button>
              : <label style={{
                  padding:'4px 10px',borderRadius:20,border:'1px dashed '+T.accent,
                  background:'rgba(74,124,63,0.08)',color:T.accent,cursor:'pointer',fontSize:11,fontWeight:600,
                  display:'flex',alignItems:'center',gap:4}}>
                  &#x1F4F7; Photo
                  <input type="file" accept="image/*" style={{display:'none'}}
                    onChange={e=>{if(e.target.files[0])handleBgFile(e.target.files[0]);}}/>
                </label>
            }
          </div>
        </div>
        <div style={{overflowX:'auto',overflowY:'auto',flex:1}}
          onMouseUp={()=>{
            setIsPainting(false);
            if(mode==='zones'&&zoneDrawStart&&zoneDrawEnd){
              const x1=Math.min(zoneDrawStart.x,zoneDrawEnd.x);
              const y1=Math.min(zoneDrawStart.y,zoneDrawEnd.y);
              const x2=Math.max(zoneDrawStart.x,zoneDrawEnd.x);
              const y2=Math.max(zoneDrawStart.y,zoneDrawEnd.y);
              setPendingZoneRect({x:x1,y:y1,w:x2-x1+1,h:y2-y1+1});
            }
            setZoneDrawStart(null);setZoneDrawEnd(null);
          }}
          onMouseLeave={()=>{setIsPainting(false);setZoneDrawStart(null);setZoneDrawEnd(null);}}>
          <div style={{position:'relative',width:gridW,height:gridH,borderRadius:10,
            outline:bgDragOver?'3px dashed '+T.accent:'none'}}
            onDragOver={e=>{
              if(e.dataTransfer.types.includes('Files')){e.preventDefault();e.dataTransfer.dropEffect='copy';setBgDragOver(true);}
              else if(e.dataTransfer.types.includes('zoneid')){e.preventDefault();e.dataTransfer.dropEffect='move';}
            }}
            onDragLeave={e=>{if(!e.currentTarget.contains(e.relatedTarget))setBgDragOver(false);}}
            onDrop={e=>{
              const zid=e.dataTransfer.getData('zoneId');
              if(zid){
                e.preventDefault();
                const rect=e.currentTarget.getBoundingClientRect();
                const cx=Math.max(0,Math.floor((e.clientX-rect.left)/(size+GP)));
                const cy=Math.max(0,Math.floor((e.clientY-rect.top)/(size+GP)));
                moveZone(zid,cx,cy);
                return;
              }
              if(e.dataTransfer.files.length>0){
                e.preventDefault();setBgDragOver(false);
                handleBgFile(e.dataTransfer.files[0]);
              }
            }}>
            {bgImage&&<div style={{position:'absolute',inset:0,borderRadius:10,overflow:'hidden',zIndex:0,pointerEvents:'none'}}>
              <img src={bgImage} alt="" style={{width:'100%',height:'100%',objectFit:'cover',opacity:0.32}}/>
            </div>}
            {bgDragOver&&!bgImage&&<div style={{position:'absolute',inset:0,zIndex:20,borderRadius:10,
              background:'rgba(74,124,63,0.12)',display:'flex',alignItems:'center',justifyContent:'center',pointerEvents:'none'}}>
              <span style={{fontSize:18,fontWeight:700,color:T.accent}}>&#x1F4F7; Drop to set as background</span>
            </div>}
            <div style={{display:'grid',gridTemplateColumns:`repeat(${cols},${size}px)`,gridTemplateRows:`repeat(${rows},${size}px)`,gap:GP,width:gridW,height:gridH,position:'relative',zIndex:1}}>
              {Array.from({length:rows},(_,y)=>Array.from({length:cols},(_,x)=>{
                const key=`${x},${y}`,plants=cellMap[key]||[],plant=plants[0]||null,multi=plants.length>1;
                const isHov=hov&&hov.x===x&&hov.y===y;
                const ph=plant?photo(plant):null,col=plant?TC[plantCategory(plant)]:null;
                const wUlvl=plant?getUrgency(plant,careLog,'watered').level:null;
                const anyOverdue=multi&&plants.some(p=>getUrgency(p,careLog,'watered').level==='overdue');
                const zone=getZn(x,y);
                const paintC=cellColor[key]||null;
                const labelTxt=cellText[key]||null;
                const isEditingThis=editCell===key&&mode==='label';
                const isDisabled=disabledCells.has(key);

                // Disabled cell — invisible gap (preserve grid position) except in shape mode
                if(isDisabled&&mode!=='shape'){
                  return <div key={key} style={{width:size,height:size,visibility:'hidden',pointerEvents:'none'}}/>;
                }

                // Border
                const border=isDisabled?'1px dashed rgba(255,255,255,0.18)'
                  :isHov&&mode==='place'?'2px dashed '+T.accent
                  :multi?'2px dashed '+T.accent
                  :plant?'2px solid '+col
                  :paintC?'2px solid '+paintC
                  :(zone?'1px solid '+zone.border:'1px dashed '+T.border);
                // Background
                const bg=isDisabled?'rgba(0,0,0,0.35)':plant?'transparent':(paintC||zone?.col||T.surface);
                // Cursor
                const cursor=mode==='zones'?'crosshair':mode==='shape'?'pointer':mode==='paint'?'crosshair':mode==='label'?'text':plant?'grab':'default';
                // Zone-draw selection highlight
                const inDrawSel=zoneDrawStart&&zoneDrawEnd&&
                  x>=Math.min(zoneDrawStart.x,zoneDrawEnd.x)&&x<=Math.max(zoneDrawStart.x,zoneDrawEnd.x)&&
                  y>=Math.min(zoneDrawStart.y,zoneDrawEnd.y)&&y<=Math.max(zoneDrawStart.y,zoneDrawEnd.y);

                return(
                  <div key={key}
                    draggable={mode==='place'&&!!plant&&!multi}
                    onDragStart={e=>{
                      if(!plant||mode!=='place'||multi)return;
                      e.dataTransfer.setData('plantId',String(plant.id));
                      e.dataTransfer.setData('fromCell',key);
                      setDragId(String(plant.id));
                      e.stopPropagation();
                    }}
                    onDragEnd={()=>setDragId(null)}
                    onDragOver={e=>{if(mode==='place'){e.preventDefault();setHov({x,y});}}}
                    onDragLeave={e=>{if(mode==='place'&&!e.currentTarget.contains(e.relatedTarget))setHov(null);}}
                    onDrop={e=>{
                      if(mode==='place'){
                        e.preventDefault();
                        const pid=e.dataTransfer.getData('plantId');
                        const fromCell=e.dataTransfer.getData('fromCell');
                        if(pid)placeAt(pid,x,y,fromCell||null);
                        setHov(null);
                      }
                    }}
                    onDoubleClick={()=>{
                      if(mode==='place'&&plant&&!isDisabled&&!multi){
                        if(clickTimerRef.current){clearTimeout(clickTimerRef.current);clickTimerRef.current=null;}
                        removeCell(x,y);
                      }
                    }}
                    onClick={()=>{
                      if(mode==='place'&&plant&&!isDisabled&&!multi){
                        if(clickTimerRef.current)clearTimeout(clickTimerRef.current);
                        clickTimerRef.current=setTimeout(()=>{onSelect(plant);clickTimerRef.current=null;},230);
                      }
                      else if(mode==='label'&&!isDisabled){setEditCell(key);setEditText(cellText[key]||'');}
                    }}
                    onMouseDown={e=>{
                      if(e.button!==0)return;
                      e.preventDefault();
                      if(mode==='paint'&&!isDisabled){setIsPainting(true);doPaint(key);}
                      else if(mode==='shape'){
                        setIsPainting(true);
                        const erasing=isDisabled;
                        setShapeErasing(erasing);
                        doShape(key,erasing);
                      }
                      else if(mode==='zones'){
                        setIsPainting(true);
                        setZoneDrawStart({x,y});setZoneDrawEnd({x,y});
                      }
                    }}
                    onMouseEnter={()=>{
                      if(!isPainting)return;
                      if(mode==='paint'&&!isDisabled)doPaint(key);
                      else if(mode==='shape')doShape(key,shapeErasing);
                      else if(mode==='zones')setZoneDrawEnd({x,y});
                    }}
                    title={
                      mode==='paint'?'Click/drag to paint'
                      :mode==='label'?'Click to edit label'
                      :multi?plants.length+' plants in this pot — click a tile to view, double-click a tile to remove it, drag another plant here to add more'
                      :plant?plant.name+' — drag to move, double-click to remove, drag another plant here to combine into one pot'
                      :(zone?zone.label:'Drag a plant here')
                    }
                    style={{width:size,height:size,borderRadius:8,overflow:'hidden',position:'relative',
                      cursor,
                      background:bg,
                      border,
                      transition:'border-color .12s,box-shadow .12s',
                      userSelect:'none',
                      boxShadow:(plant&&wUlvl==='overdue')||anyOverdue?'0 0 8px rgba(239,68,68,.55)':'none'}}>
                    {/* Disabled cell — show X hint in shape mode */}
                    {isDisabled&&mode==='shape'&&<div style={{
                      position:'absolute',inset:0,display:'flex',alignItems:'center',
                      justifyContent:'center',fontSize:16,color:'rgba(255,255,255,0.35)',
                      userSelect:'none',pointerEvents:'none',zIndex:2}}>&#x2715;</div>}
                    {/* Paint colour tint on painted cells (shows even with plant) */}
                    {!isDisabled&&paintC&&plant&&<div style={{position:'absolute',inset:0,background:paintC,opacity:0.22,zIndex:0,pointerEvents:'none'}}/>}
                    {/* Single-plant cell: full photo + name */}
                    {!isDisabled&&!multi&&ph&&plant&&<img src={ph} alt={plant.name} style={{width:'100%',height:'100%',objectFit:'cover',position:'relative',zIndex:1}}/>}
                    {!isDisabled&&!multi&&plant&&<div style={{position:'absolute',bottom:0,left:0,right:0,zIndex:2,
                      background:'linear-gradient(transparent,rgba(0,0,0,.82))',padding:'16px 3px 4px',
                      fontSize:9,color:'#fff',fontWeight:700,textAlign:'center',lineHeight:1.2}}>
                      {plant.name.length>13?plant.name.slice(0,11)+'…':plant.name}
                    </div>}
                    {!isDisabled&&!multi&&plant&&<div style={{position:'absolute',top:3,right:3,width:8,height:8,zIndex:3,borderRadius:'50%',background:col,boxShadow:'0 0 0 1px rgba(0,0,0,.35)'}}/>}
                    {!isDisabled&&!multi&&plant&&wUlvl==='overdue'&&<div style={{position:'absolute',top:3,left:3,zIndex:3,background:'#ef4444',color:'#fff',borderRadius:'50%',width:14,height:14,fontSize:9,display:'flex',alignItems:'center',justifyContent:'center',fontWeight:900}}>!</div>}
                    {!isDisabled&&!multi&&plant&&paintC&&<div style={{position:'absolute',bottom:3,left:3,width:8,height:8,zIndex:4,borderRadius:'50%',background:paintC,border:'1px solid rgba(0,0,0,0.4)'}}/>}
                    {/* Multi-plant (mixed pot) cell: mini-tiles in a single horizontal row, one per plant */}
                    {!isDisabled&&multi&&(
                      <div style={{position:'absolute',inset:0,display:'flex',
                        flexDirection:'row',gap:1,padding:1,zIndex:1}}>
                        {plants.map((p,i)=>{
                          const pph=photo(p),pcol=TC[plantCategory(p)];
                          const pU=getUrgency(p,careLog,'watered').level;
                          return (
                            <div key={p.id+':'+i}
                              draggable={mode==='place'}
                              onDragStart={e=>{
                                if(mode!=='place')return;
                                e.dataTransfer.setData('plantId',String(p.id));
                                e.dataTransfer.setData('fromCell',key);
                                setDragId(String(p.id));
                                e.stopPropagation();
                              }}
                              onDragEnd={()=>setDragId(null)}
                              onClick={e=>{
                                e.stopPropagation();
                                if(mode==='place'&&!isDisabled){
                                  if(clickTimerRef.current)clearTimeout(clickTimerRef.current);
                                  clickTimerRef.current=setTimeout(()=>{onSelect(p);clickTimerRef.current=null;},230);
                                }
                              }}
                              onDoubleClick={e=>{
                                e.stopPropagation();
                                if(mode==='place'&&!isDisabled){
                                  if(clickTimerRef.current){clearTimeout(clickTimerRef.current);clickTimerRef.current=null;}
                                  removeCell(x,y,p.id);
                                }
                              }}
                              title={p.name+' — drag to move out, double-click to remove from this pot'}
                              style={{position:'relative',flex:'1 1 0',minWidth:0,borderRadius:3,overflow:'hidden',
                                border:'1px solid '+pcol,cursor:mode==='place'?'grab':'default',
                                background:T.surface}}>
                              {pph&&<img src={pph} alt={p.name} style={{width:'100%',height:'100%',objectFit:'cover'}}/>}
                              {pU==='overdue'&&<div style={{position:'absolute',top:1,left:1,background:'#ef4444',color:'#fff',
                                borderRadius:'50%',width:10,height:10,fontSize:7,display:'flex',alignItems:'center',justifyContent:'center',fontWeight:900}}>!</div>}
                            </div>
                          );
                        })}
                      </div>
                    )}
                    {!isDisabled&&multi&&<div style={{position:'absolute',bottom:0,left:0,right:0,zIndex:2,pointerEvents:'none',
                      background:'linear-gradient(transparent,rgba(0,0,0,.85))',padding:'10px 2px 2px',
                      fontSize:7,color:'#fff',fontWeight:700,textAlign:'center',lineHeight:1.1}}>
                      {plants.length} plants
                    </div>}
                    {/* Text label */}
                    {labelTxt&&!isEditingThis&&<div style={{
                      position:'absolute',zIndex:5,
                      bottom:plant?18:4,left:2,right:2,
                      textAlign:'center',fontSize:8,fontWeight:700,
                      color:'#fff',textShadow:'0 1px 3px rgba(0,0,0,1)',
                      lineHeight:1.2,wordBreak:'break-word',overflow:'hidden',maxHeight:plant?14:32}}>
                      {labelTxt}
                    </div>}
                    {/* Hover + indicator */}
                    {isHov&&mode==='place'&&!plant&&<div style={{position:'absolute',inset:0,zIndex:5,display:'flex',alignItems:'center',justifyContent:'center',fontSize:22,color:T.accent,opacity:.55}}>+</div>}
                    {isHov&&mode==='place'&&!!plant&&<div style={{position:'absolute',top:2,right:multi?2:14,zIndex:6,fontSize:13,color:T.accent,background:'rgba(0,0,0,0.55)',borderRadius:'50%',width:16,height:16,display:'flex',alignItems:'center',justifyContent:'center',pointerEvents:'none'}}>+</div>}
                    {inDrawSel&&<div style={{position:'absolute',inset:0,background:'rgba(99,102,241,0.35)',zIndex:6,pointerEvents:'none',borderRadius:4}}/>}
                    {mode==='label'&&!isEditingThis&&<div style={{position:'absolute',top:2,left:2,fontSize:9,zIndex:5,opacity:0.45}}>&#x270F;</div>}
                    {/* Inline text editor (label mode) */}
                    {isEditingThis&&(
                      <div style={{position:'absolute',inset:0,zIndex:10,display:'flex',flexDirection:'column',
                        alignItems:'center',justifyContent:'center',background:'rgba(0,0,0,0.72)',borderRadius:6,padding:4}}>
                        <input autoFocus value={editText}
                          onChange={e=>setEditText(e.target.value)}
                          placeholder="Label…"
                          onKeyDown={e=>{
                            if(e.key==='Enter'){e.preventDefault();saveCellText(key,editText);}
                            if(e.key==='Escape'){setEditCell(null);}
                          }}
                          onBlur={()=>saveCellText(key,editText)}
                          style={{width:'100%',padding:'3px 5px',borderRadius:4,border:'1px solid '+T.accent,
                            background:T.input,color:T.text,fontSize:10,outline:'none',boxSizing:'border-box',textAlign:'center'}}/>
                        <div style={{display:'flex',gap:4,marginTop:3}}>
                          <button onMouseDown={e=>{e.preventDefault();saveCellText(key,'');}}
                            style={{fontSize:8,padding:'2px 5px',borderRadius:3,border:'none',
                              background:'rgba(239,68,68,0.8)',color:'#fff',cursor:'pointer'}}>Clear</button>
                          <button onMouseDown={e=>{e.preventDefault();saveCellText(key,editText);}}
                            style={{fontSize:8,padding:'2px 5px',borderRadius:3,border:'none',
                              background:T.green,color:'#fff',cursor:'pointer'}}>Save</button>
                        </div>
                      </div>
                    )}
                  </div>
                );
              }))}
            </div>
            {/* Zone label overlays — draggable in place mode, editable/deletable in zones mode */}
            {effectiveZones.map(z=>{
              const zp=getZonePos(z);
              const draggable=mode==='place';
              const editable=mode==='zones';
              const isEditThis=editingZoneId===z.id;
              return(
                <div key={z.id}
                  style={{
                    position:'absolute',
                    left:zp.x*(size+GP),top:zp.y*(size+GP),
                    width:z.w*(size+GP)-GP,height:z.h*(size+GP)-GP,
                    pointerEvents:'none',
                    display:'flex',alignItems:'flex-start',justifyContent:'center',
                    paddingTop:6,zIndex:5}}>
                  {editable?(
                    <div style={{display:'flex',alignItems:'center',gap:4,
                      background:'rgba(0,0,0,0.72)',borderRadius:5,padding:'3px 6px',
                      maxWidth:'90%',backdropFilter:'blur(3px)',pointerEvents:'auto'}}>
                      {isEditThis?(
                        <input autoFocus value={editingZoneLabelVal}
                          onChange={e=>setEditingZoneLabelVal(e.target.value)}
                          onKeyDown={e=>{if(e.key==='Enter')saveZoneLabel(z.id,editingZoneLabelVal);if(e.key==='Escape')setEditingZoneId(null);}}
                          onBlur={()=>saveZoneLabel(z.id,editingZoneLabelVal)}
                          style={{width:80,padding:'2px 4px',borderRadius:3,border:'1px solid '+T.accent,
                            background:T.input,color:T.text,fontSize:10,outline:'none'}}/>
                      ):(
                        <span onClick={()=>{setEditingZoneId(z.id);setEditingZoneLabelVal(z.label);}}
                          style={{color:'#fff',fontSize:10,fontWeight:700,cursor:'text',userSelect:'none',
                            letterSpacing:.3,lineHeight:1.3}}>
                          &#x270F; {z.label}
                        </span>
                      )}
                      <button onMouseDown={e=>{e.preventDefault();e.stopPropagation();removeZone(z.id);}}
                        style={{background:'rgba(239,68,68,0.85)',border:'none',borderRadius:3,
                          color:'#fff',fontSize:11,fontWeight:700,cursor:'pointer',lineHeight:1,
                          padding:'1px 4px',flexShrink:0}}>
                        &#x2715;
                      </button>
                    </div>
                  ):(
                    <span
                      draggable={draggable}
                      onDragStart={draggable?e=>{
                        e.dataTransfer.setData('zoneId',z.id);
                        e.dataTransfer.effectAllowed='move';
                        e.stopPropagation();
                      }:undefined}
                      style={{
                      background:'rgba(0,0,0,.52)',color:'#fff',fontSize:10,fontWeight:700,
                      borderRadius:4,padding:'2px 7px',letterSpacing:.3,backdropFilter:'blur(2px)',
                      maxWidth:'90%',textAlign:'center',lineHeight:1.3,pointerEvents:draggable?'auto':'none',
                      userSelect:'none',display:'flex',alignItems:'center',gap:4,cursor:draggable?'grab':'default'}}>
                      {draggable&&<span style={{opacity:0.7,fontSize:12}}>&#x2B0C;</span>}
                      {z.label}
                    </span>
                  )}
                </div>
              );
            })}
          </div>{/* end position:relative outer */}
        </div>{/* end overflow scroll */}
      </div>
    </div>
    {/* ── New-zone confirmation modal ─────────────────────────────────── */}
    {pendingZoneRect&&(
      <div style={{position:'fixed',inset:0,zIndex:3000,display:'flex',alignItems:'center',justifyContent:'center',
        background:'rgba(0,0,0,0.55)'}}
        onMouseDown={e=>{if(e.target===e.currentTarget){setPendingZoneRect(null);}}}>
        <div style={{background:T.card,border:'1px solid '+T.border,borderRadius:14,padding:20,
          width:320,boxShadow:'0 8px 32px rgba(0,0,0,0.5)'}}>
          <div style={{fontWeight:700,fontSize:15,color:T.text,marginBottom:14}}>
            &#x1F5FA;&#xFE0F; New Zone ({pendingZoneRect.w}&times;{pendingZoneRect.h} cells)
          </div>
          <div style={{marginBottom:10}}>
            <label style={{fontSize:12,color:T.sub,display:'block',marginBottom:4}}>Zone name</label>
            <input autoFocus value={newZoneLabel} onChange={e=>setNewZoneLabel(e.target.value)}
              onKeyDown={e=>{if(e.key==='Enter')confirmNewZone();if(e.key==='Escape')setPendingZoneRect(null);}}
              placeholder="e.g. Sunny corner"
              style={{width:'100%',padding:'7px 10px',borderRadius:7,border:'1px solid '+T.border,
                background:T.input,color:T.text,fontSize:13,outline:'none',boxSizing:'border-box'}}/>
          </div>
          <div style={{marginBottom:16}}>
            <label style={{fontSize:12,color:T.sub,display:'block',marginBottom:6}}>Colour</label>
            <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
              {ZONE_COLORS.map((c,i)=>(
                <div key={i} onClick={()=>setNewZoneColorIdx(i)}
                  style={{width:24,height:24,borderRadius:5,background:c.border,cursor:'pointer',flexShrink:0,
                    border:newZoneColorIdx===i?'3px solid '+T.text:'2px solid transparent',
                    outline:newZoneColorIdx===i?'1px solid '+T.accent:'none',outlineOffset:1,
                    boxSizing:'border-box'}}/>
              ))}
            </div>
          </div>
          <div style={{display:'flex',gap:8}}>
            <button onClick={()=>setPendingZoneRect(null)} style={{
              flex:1,padding:'8px 0',borderRadius:7,border:'1px solid '+T.border,
              background:T.input,color:T.sub,cursor:'pointer',fontSize:13}}>
              Cancel
            </button>
            <button onClick={confirmNewZone} style={{
              flex:2,padding:'8px 0',borderRadius:7,border:'none',
              background:T.green,color:'#fff',cursor:'pointer',fontSize:13,fontWeight:700}}>
              Add Zone
            </button>
          </div>
        </div>
      </div>
    )}
    </>
  );
}

// ─── WeatherWidget ─────────────────────────────────────────────────────────
const WMO_ICON=c=>c===0?'☀️':c<=2?'⛅':c===3?'☁️':c<=49?'🌫️':c<=69?'🌧️':c<=79?'🌨️':c<=84?'🌦️':'⛈️';
const WMO_DESC=c=>c===0?'Clear sky':c===1?'Mainly clear':c===2?'Partly cloudy':c===3?'Overcast':c<=49?'Foggy':c<=69?'Rainy':c<=79?'Snowy':c<=84?'Showers':'Thunderstorm';
function WeatherWidget(){
  const T=React.useContext(ThemeCtx);
  const [w,setW]=React.useState(null);
  React.useEffect(()=>{
    fetch('https://api.open-meteo.com/v1/forecast?latitude=51.45&longitude=0.05&current=temperature_2m,apparent_temperature,weather_code,relative_humidity_2m,wind_speed_10m&timezone=Europe%2FLondon&wind_speed_unit=mph')
      .then(r=>r.json()).then(d=>{if(d&&d.current)setW(d.current);}).catch(()=>{});
  },[]);
  if(!w) return(
    <div style={{background:T.card,borderRadius:14,padding:'12px 18px',border:'1px solid '+T.border,
      marginBottom:20,fontSize:12,color:T.sub}}>
      Loading London SE weather...
    </div>
  );
  return(
    <div style={{background:T.card,borderRadius:14,padding:'14px 20px',border:'1px solid '+T.border,
      display:'flex',alignItems:'center',gap:20,flexWrap:'wrap',marginBottom:20}}>
      <div>
        <div style={{fontSize:10,color:T.sub,marginBottom:4,textTransform:'uppercase',letterSpacing:.5,fontWeight:600}}>London SE &bull; Live Weather</div>
        <div style={{display:'flex',alignItems:'center',gap:10}}>
          <span style={{fontSize:36,lineHeight:1}}>{WMO_ICON(w.weather_code)}</span>
          <div>
            <div style={{fontSize:30,fontWeight:800,color:T.text,lineHeight:1}}>{Math.round(w.temperature_2m)}&deg;C</div>
            <div style={{fontSize:11,color:T.sub}}>Feels like {Math.round(w.apparent_temperature)}&deg;C &bull; {WMO_DESC(w.weather_code)}</div>
          </div>
        </div>
      </div>
      <div style={{display:'flex',gap:16,flexWrap:'wrap'}}>
        {[
          ['💧',w.relative_humidity_2m+'%','Humidity'],
          ['💨',Math.round(w.wind_speed_10m)+' mph','Wind'],
        ].map(([icon,val,lbl])=>(
          <div key={lbl} style={{textAlign:'center'}}>
            <div style={{fontSize:18,lineHeight:1.2}}>{icon}</div>
            <div style={{fontSize:13,fontWeight:700,color:T.text}}>{val}</div>
            <div style={{fontSize:10,color:T.sub}}>{lbl}</div>
          </div>
        ))}
      </div>
      <div style={{marginLeft:'auto',fontSize:10,color:T.sub,textAlign:'right'}}>
        <div>Updated on page load</div>
        <div>SE London (51.45&deg;N, 0.05&deg;E)</div>
      </div>
    </div>
  );
}

// ─── NotificationManager ───────────────────────────────────────────────────
function NotificationManager({allPlants, careLog}){
  const T=React.useContext(ThemeCtx);
  const [perm,setPerm]=React.useState(typeof Notification!=='undefined'?Notification.permission:'denied');

  function doNotify(){
    if(typeof Notification==='undefined'||Notification.permission!=='granted') return;
    const overdueW=allPlants.filter(p=>getUrgency(p,careLog,'watered').level==='overdue');
    const overdueF=allPlants.filter(p=>getUrgency(p,careLog,'fed').level==='overdue');
    if(overdueW.length){
      new Notification('Plant Watering',{body:overdueW.length+' plant'+(overdueW.length>1?'s':'')+' need water: '+overdueW.slice(0,3).map(p=>p.name).join(', ')+(overdueW.length>3?'...':'')});
    }
    if(overdueF.length){
      new Notification('Plant Feeding',{body:overdueF.length+' plant'+(overdueF.length>1?'s':'')+' need feeding'});
    }
    if(!overdueW.length&&!overdueF.length){
      new Notification('All Good',{body:'No plants are overdue right now.'});
    }
    try{localStorage.setItem('plant-notif-last',String(Date.now()));}catch{}
  }

  React.useEffect(()=>{
    if(perm==='granted'){
      const last=Number(localStorage.getItem('plant-notif-last')||0);
      if(Date.now()-last>3600000) doNotify();
    }
  },[perm]);

  async function enable(){
    if(typeof Notification==='undefined') return;
    const r=await Notification.requestPermission();
    setPerm(r);
  }

  if(typeof Notification==='undefined') return null;
  return (
    <div style={{marginLeft:'auto'}}>
      {perm==='default'&&(
        <button onClick={enable} style={{padding:'5px 12px',background:'#3b82f6',border:'none',
          borderRadius:20,color:'#fff',fontSize:12,cursor:'pointer',fontWeight:600}}>
          &#x1F514; Enable reminders
        </button>
      )}
      {perm==='granted'&&(
        <button onClick={doNotify} style={{padding:'5px 12px',background:T.input,
          border:'1px solid '+T.border,borderRadius:20,color:T.text,fontSize:12,cursor:'pointer'}}>
          &#x1F514; Check now
        </button>
      )}
      {perm==='denied'&&(
        <span style={{fontSize:11,color:T.sub}}>&#x1F514; Notifications blocked</span>
      )}
    </div>
  );
}

// ─── IrrigationMap — read-only watering-need view derived from live map placements ──
function IrrigationSection({title,storageKey,fallback,cfg,allPlants}){
  const T=React.useContext(ThemeCtx);
  const GP=4;
  const pos=(()=>{
    try{const s=JSON.parse(localStorage.getItem(storageKey)||'null');return s||fallback||{};}
    catch{return fallback||{};}
  })();
  const {cols,rows,size}=cfg;
  const gridW=cols*(size+GP)-GP, gridH=rows*(size+GP)-GP;
  const entries=Object.entries(pos);
  return (
    <div style={{marginBottom:28}}>
      <h3 style={{fontSize:16,fontWeight:700,color:T.text,marginBottom:10}}>{title}</h3>
      {entries.length===0?(
        <div style={{padding:20,textAlign:'center',color:T.sub,fontSize:13,
          background:T.surface,borderRadius:10,border:'1px dashed '+T.border}}>
          No plants placed on the {title} map yet.
        </div>
      ):(
        <div style={{overflowX:'auto'}}>
          <div style={{display:'grid',gridTemplateColumns:`repeat(${cols},${size}px)`,
            gridTemplateRows:`repeat(${rows},${size}px)`,gap:GP,width:gridW,height:gridH}}>
            {Array.from({length:rows},(_,y)=>Array.from({length:cols},(_,x)=>{
              const key=`${x},${y}`;
              const val=pos[key];
              const plants=val?String(val).split(',').filter(Boolean)
                .map(id=>allPlants.find(p=>String(p.id)===id)).filter(Boolean):[];
              if(!plants.length){
                return <div key={key} style={{width:size,height:size,borderRadius:8,
                  border:'1px dashed '+T.border,background:T.surface}}/>;
              }
              const levels=plants.map(waterLevel);
              const worst=levels.includes('high')?'high':levels.includes('med')?'med':'low';
              const c=WATER_LEVEL_COLORS[worst];
              const names=plants.map(p=>p.name).join(', ');
              return (
                <div key={key}
                  title={plants.map(p=>p.name+' — '+WATER_LEVEL_COLORS[waterLevel(p)].label+' water need').join('\n')}
                  style={{width:size,height:size,borderRadius:8,background:c.bg,
                    border:'2px solid '+c.border,display:'flex',alignItems:'center',
                    justifyContent:'center',padding:3,overflow:'hidden',cursor:'default'}}>
                  <span style={{fontSize:8,color:'#fff',fontWeight:700,textAlign:'center',
                    lineHeight:1.15,textShadow:'0 1px 2px rgba(0,0,0,.65)',
                    display:'-webkit-box',WebkitLineClamp:4,WebkitBoxOrient:'vertical',overflow:'hidden'}}>
                    {names}
                  </span>
                </div>
              );
            }))}
          </div>
        </div>
      )}
    </div>
  );
}
function IrrigationMap({allPlants}){
  const T=React.useContext(ThemeCtx);
  const MAP_BASE_SIZE={courtyard:{cols:14,rows:8,size:76},garden:{cols:14,rows:9,size:76}};
  function getCfg(k){
    let ms={};
    try{ms=JSON.parse(localStorage.getItem('map-settings')||'{}');}catch{}
    return {...MAP_BASE_SIZE[k],...(ms[k]||{})};
  }
  return (
    <div>
      <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:12,flexWrap:'wrap'}}>
        <h2 style={{fontSize:20,fontWeight:700,color:T.text,margin:0}}>&#x1F4A7; Irrigation System</h2>
        <div style={{display:'flex',gap:14,alignItems:'center',marginLeft:'auto',flexWrap:'wrap'}}>
          {['low','med','high'].map(k=>{
            const c=WATER_LEVEL_COLORS[k];
            return (
              <div key={k} style={{display:'flex',alignItems:'center',gap:5}}>
                <div style={{width:14,height:14,borderRadius:4,background:c.bg,border:'2px solid '+c.border}}/>
                <span style={{fontSize:12,color:T.sub}}>{c.label}</span>
              </div>
            );
          })}
        </div>
      </div>
      <p style={{color:T.sub,fontSize:13,marginBottom:20}}>
        Colour reflects each plant's watering need, worked out automatically from its care info
        (Low / Medium / High). A shared pot is coloured by the highest need among its plants.
        This mirrors whatever is currently placed on the Courtyard and Back Garden maps — change
        placements there and this view updates to match.
      </p>
      <IrrigationSection title="Courtyard" storageKey="courtyard-map" fallback={COURTYARD_DEFAULT} cfg={getCfg('courtyard')} allPlants={allPlants}/>
      <IrrigationSection title="Back Garden" storageKey="garden-map" fallback={null} cfg={getCfg('garden')} allPlants={allPlants}/>
    </div>
  );
}

// ─── Catalogue ─────────────────────────────────────────────────────────────
function Catalogue(){
  const [dark,    setDark]    = React.useState(true);
  const [view,    setView]    = React.useState('catalogue');
  const [mapTab,  setMapTab]  = React.useState('garden');
  const [mapFull, setMapFull] = React.useState(false);
  const [showMapSettings, setShowMapSettings] = React.useState(false);
  const [mapSettings, setMapSettings] = React.useState(()=>{
    try{return JSON.parse(localStorage.getItem('map-settings')||'{}');}catch{return {};}
  });
  const MAP_SIZE_DEFAULTS={
    garden:    {cols:14,rows:9, size:76},
    courtyard: {cols:14,rows:8, size:76},
    greenhouse:{cols:7, rows:9, size:86},
    indoor:    {cols:16,rows:10,size:64},
  };
  function getMapCfg(k){return{...MAP_SIZE_DEFAULTS[k],...(mapSettings[k]||{})};}
  function updateMapCfg(k,patch){
    const next={...mapSettings,[k]:{...((mapSettings[k])||{}),...patch}};
    setMapSettings(next);
    try{localStorage.setItem('map-settings',JSON.stringify(next));}catch{}
  }
  function resetMapCfg(k){
    const next={...mapSettings};delete next[k];
    setMapSettings(next);
    try{localStorage.setItem('map-settings',JSON.stringify(next));}catch{}
  }
  function resetMapLayout(k){
    if(!window.confirm(`Reset the ${getMapName(k)} map layout? This clears all plant placements, custom zones, labels, colours and any background photo you've set for this map, restoring the built-in defaults.`))return;
    const sk=k+'-map';
    ['','-text','-color','-disabled','-czones','-rzones','-zlabels','-bg'].forEach(suffix=>{
      try{localStorage.removeItem(sk+suffix);}catch{}
    });
    window.location.reload();
  }
  const MAP_DEFAULTS={garden:'Back Garden',courtyard:'Courtyard',greenhouse:'Greenhouse',indoor:'Indoor'};
  const MAP_ICONS={garden:'&#x1F33B;',courtyard:'&#x2600;&#xFE0F;',greenhouse:'&#x1F9EA;',indoor:'&#x1F3E0;'};
  const [mapNames,setMapNames]=React.useState(()=>{
    try{return JSON.parse(localStorage.getItem('map-names')||'{}');}catch{return {};}
  });
  const [editingMap,setEditingMap]=React.useState(null);
  const [editingName,setEditingName]=React.useState('');
  function getMapName(k){return mapNames[k]||MAP_DEFAULTS[k]||k;}
  function saveMapName(k,v){
    const n={...mapNames,[k]:v.trim()||MAP_DEFAULTS[k]};
    setMapNames(n);
    try{localStorage.setItem('map-names',JSON.stringify(n));}catch{}
    setEditingMap(null);
  }
  const [search,  setSearch]  = React.useState('');
  const [tags,    setTags]    = React.useState([]);
  const [selected,setSelected]= React.useState(null);
  const [careLog, setCareLog] = React.useState(()=>{
    try{ return JSON.parse(localStorage.getItem('plant-care-log')||'{}'); }catch{ return {}; }
  });
  const [notes,   setNotes]   = React.useState(()=>{
    try{ return JSON.parse(localStorage.getItem('plant-notes')||'{}'); }catch{ return {}; }
  });
  const [harvests,setHarvests]= React.useState(()=>{
    try{ return JSON.parse(localStorage.getItem('plant-harvests')||'{}'); }catch{ return {}; }
  });
  const [lightboxSrc,setLightboxSrc] = React.useState(null);
  const [coverY,  setCoverY]  = React.useState(50); // kept for compat
  const [pestLog,  setPestLog]  = React.useState(()=>{try{return JSON.parse(localStorage.getItem('plant-pests')||'[]');}catch{return [];}});
  const [wishlist, setWishlist] = React.useState(()=>{try{return JSON.parse(localStorage.getItem('plant-wishlist')||'[]');}catch{return [];}});
  const [careHistory, setCareHistory] = React.useState(()=>{try{return JSON.parse(localStorage.getItem('plant-care-history')||'{}');}catch{return {};}});
  const [bulkWaterModal, setBulkWaterModal] = React.useState(false);
  const [pestModal, setPestModal] = React.useState(null);

  const T = dark ? DARK : LIGHT;
  const allPlants = React.useMemo(()=>[...OUTDOOR_PLANTS,...INDOOR_PLANTS,...HYDRO_PLANTS],[]);

  React.useEffect(()=>{
    const onScroll=()=>setCoverY(Math.min(80,50+window.scrollY*0.03));
    window.addEventListener('scroll',onScroll,{passive:true});
    return()=>window.removeEventListener('scroll',onScroll);
  },[]);

  function logCare(plantId, type){
    const ts = Date.now();
    const updated = {...careLog, [String(plantId)+'-'+type]: ts};
    setCareLog(updated);
    try{ localStorage.setItem('plant-care-log',JSON.stringify(updated)); }catch{}
    const hKey=String(plantId)+'-'+type;
    const updH={...careHistory,[hKey]:[ts,...(careHistory[hKey]||[])].slice(0,30)};
    setCareHistory(updH);
    try{ localStorage.setItem('plant-care-history',JSON.stringify(updH)); }catch{}
  }
  function addNote(plantId, text){
    const key=String(plantId), existing=notes[key]||[];
    const updated={...notes,[key]:[{date:Date.now(),text},...existing].slice(0,10)};
    setNotes(updated);
    try{ localStorage.setItem('plant-notes',JSON.stringify(updated)); }catch{}
  }
  function addHarvest(plantId,qty,note){
    const key=String(plantId), existing=harvests[key]||[];
    const updated={...harvests,[key]:[{date:Date.now(),qty,note},...existing].slice(0,20)};
    setHarvests(updated);
    try{ localStorage.setItem('plant-harvests',JSON.stringify(updated)); }catch{}
  }
  function logPest(plantId, pest, note){
    const entry={id:Date.now(),plantId:String(plantId),pest,note,date:Date.now(),resolved:false};
    const updated=[entry,...pestLog];
    setPestLog(updated);
    try{ localStorage.setItem('plant-pests',JSON.stringify(updated)); }catch{}
  }
  function resolvePest(id){
    const updated=pestLog.map(e=>e.id===id?{...e,resolved:true}:e);
    setPestLog(updated);
    try{ localStorage.setItem('plant-pests',JSON.stringify(updated)); }catch{}
  }
  function addWish(name,latin,notes){
    const item={id:Date.now(),name,latin,notes,added:Date.now()};
    const updated=[item,...wishlist];
    setWishlist(updated);
    try{ localStorage.setItem('plant-wishlist',JSON.stringify(updated)); }catch{}
  }
  function removeWish(id){
    const updated=wishlist.filter(i=>i.id!==id);
    setWishlist(updated);
    try{ localStorage.setItem('plant-wishlist',JSON.stringify(updated)); }catch{}
  }
  function bulkWater(){
    const overdue=allPlants.filter(p=>getUrgency(p,careLog,'watered').level==='overdue');
    const ts=Date.now();
    const updL={...careLog}, updH={...careHistory};
    overdue.forEach(p=>{
      const k=String(p.id)+'-watered';
      updL[k]=ts;
      updH[k]=[ts,...(updH[k]||[])].slice(0,30);
    });
    setCareLog(updL); setCareHistory(updH);
    try{localStorage.setItem('plant-care-log',JSON.stringify(updL));}catch{}
    try{localStorage.setItem('plant-care-history',JSON.stringify(updH));}catch{}
    setBulkWaterModal(false);
  }

  const allTags = React.useMemo(()=>[...new Set(allPlants.flatMap(p=>p.tags||[]))].sort(),[allPlants]);

  function toggleTag(t){ setTags(ts=>ts.includes(t)?ts.filter(x=>x!==t):[...ts,t]); }

  function filterPlants(arr){
    return arr.filter(p=>{
      const q=search.toLowerCase();
      const matchSearch = !q||(p.name+p.latin+(p.desc||'')).toLowerCase().includes(q);
      const matchTags   = !tags.length||tags.every(t=>(p.tags||[]).includes(t));
      return matchSearch&&matchTags;
    });
  }

  const fOutdoor = filterPlants(OUTDOOR_PLANTS);
  const fIndoor  = filterPlants(INDOOR_PLANTS);
  const fHydro   = filterPlants(HYDRO_PLANTS);
  const attention = allPlants.filter(p=>getUrgency(p,careLog,'watered').level==='overdue').length;

  const sectionHdr = (label,count) => (
    <h2 className="section-hdr" style={{fontSize:18,fontWeight:700,color:T.accent,marginBottom:16,marginTop:32,
      display:'flex',alignItems:'center',gap:10}}>
      <span dangerouslySetInnerHTML={{__html:label}}/>
      <span style={{fontSize:13,color:T.sub,fontWeight:400}}>{count} plants</span>
    </h2>
  );

  const M = useIsMobile();
  const scrolled = useScrollCollapse();
  const CSS = `
    *{box-sizing:border-box;margin:0;padding:0;}
    body{background:${T.bg};color:${T.text};font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;min-height:100vh;}
    ::-webkit-scrollbar{width:6px;height:6px;}
    ::-webkit-scrollbar-track{background:${T.bg};}
    ::-webkit-scrollbar-thumb{background:${dark?'#2a3a2a':'#90b080'};border-radius:4px;}
    @keyframes spin{to{transform:rotate(360deg)}}
    @keyframes pulse{0%,100%{opacity:1}50%{opacity:0.5}}
    @keyframes kb0{0%{transform:scale(1.0) translate(0%,0%)}100%{transform:scale(1.12) translate(-2%,-1%)}}
    @keyframes kb1{0%{transform:scale(1.1) translate(-1%,0%)}100%{transform:scale(1.0) translate(1%,1%)}}
    @keyframes kb2{0%{transform:scale(1.0) translate(1%,1%)}100%{transform:scale(1.12) translate(-1%,-2%)}}
    @keyframes kb3{0%{transform:scale(1.1) translate(0%,1%)}100%{transform:scale(1.0) translate(-1%,-1%)}}
    @keyframes cardIn{from{opacity:0;transform:translateY(22px) scale(0.96)}to{opacity:1;transform:translateY(0) scale(1)}}
    @keyframes hdrIn{from{opacity:0;transform:translateX(-18px)}to{opacity:1;transform:translateX(0)}}
    @keyframes urgPulse{0%,100%{box-shadow:0 0 0 0 currentColor}60%{box-shadow:0 0 0 5px transparent}}
    @keyframes chipPop{0%{transform:scale(1)}40%{transform:scale(1.18)}100%{transform:scale(1)}}
    @keyframes fadeIn{from{opacity:0}to{opacity:1}}
    .plant-card{transition:transform 0.22s ease,box-shadow 0.22s ease;cursor:pointer;will-change:transform;}
    .plant-card:hover{transform:translateY(-6px) scale(1.015);box-shadow:0 12px 32px rgba(0,0,0,0.45);}
    .plant-card:active{transform:translateY(-2px) scale(1.005);}
    .urg-overdue{animation:urgPulse 1.6s ease-in-out infinite;color:rgba(239,68,68,0.7);}
    .urg-soon{animation:urgPulse 3s ease-in-out infinite;color:rgba(234,179,8,0.6);}
    .section-hdr{animation:hdrIn 0.4s ease both;}
    .chip-active{animation:chipPop 0.25s ease both;}
    .cards-grid{animation:fadeIn 0.3s ease both;}
    .chip-row::-webkit-scrollbar{display:none;}
    input::placeholder{color:${T.sub};opacity:0.7;}
    button,input,select{-webkit-tap-highlight-color:transparent;}
    @media(max-width:639px){html{font-size:15px;}}
    @media(prefers-reduced-motion:reduce){.plant-card,.plant-card:hover,.section-hdr,.cards-grid{animation:none;transition:none;transform:none;}}
  `;

  const navBtn = (key,label,extra='') => (
    <button onClick={()=>setView(key)} style={{
      padding:'8px 18px', border:'none', borderRadius:20,cursor:'pointer',fontSize:14,fontWeight:500,
      background:view===key?T.green:T.input, color:view===key?'#fff':T.text,
      position:'relative',
    }}>
      <span dangerouslySetInnerHTML={{__html:label}}/>
      {extra&&<span style={{background:'#ef4444',color:'#fff',borderRadius:'50%',
        width:18,height:18,fontSize:10,display:'inline-flex',alignItems:'center',
        justifyContent:'center',marginLeft:6,fontWeight:700}}>{extra}</span>}
    </button>
  );

  return (
    <ThemeCtx.Provider value={T}>
      <style>{CSS}</style>
      {/* ── Cover Slideshow ── */}
      <div style={{position:'relative',height:M?220:320,overflow:'hidden',background:'#061006'}}>
        <CoverSlideshow allPlants={allPlants}/>
        {/* gradient overlay — dark at top/bottom, lighter in centre */}
        <div style={{position:'absolute',inset:0,
          background:'linear-gradient(to bottom, rgba(0,0,0,0.35) 0%, rgba(0,0,0,0.1) 45%, rgba(0,0,0,0.55) 100%)',
          pointerEvents:'none'}}/>
        {/* Title */}
        <div style={{position:'absolute',inset:0,display:'flex',flexDirection:'column',
          alignItems:'center',justifyContent:'center',textAlign:'center',padding:20,pointerEvents:'none'}}>
          <h1 style={{fontSize:'clamp(26px,5vw,52px)',fontWeight:900,color:'#fff',
            textShadow:'0 2px 20px rgba(0,0,0,0.8)',letterSpacing:-0.5,marginBottom:6,
            fontFamily:'-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif'}}>
            &#x1F331; Marty's Plant Haven
          </h1>
          <p style={{color:'rgba(255,255,255,0.8)',fontSize:M?12:14,
            textShadow:'0 1px 8px rgba(0,0,0,0.7)',letterSpacing:.3}}>
            <span style={{color:'#86efac'}}>{OUTDOOR_PLANTS.length} outdoor</span>
            &nbsp;&bull;&nbsp;
            <span style={{color:'#93c5fd'}}>{INDOOR_PLANTS.length} indoor</span>
            &nbsp;&bull;&nbsp;
            <span style={{color:'#fcd34d'}}>{HYDRO_PLANTS.length} greenhouse</span>
            &nbsp;&bull;&nbsp;
            {allPlants.length} plants
          </p>
        </div>
        {/* Dark/Light toggle */}
        <button onClick={()=>setDark(d=>!d)}
          dangerouslySetInnerHTML={{__html: dark?'&#x2600; Light':'&#x1F319; Dark'}}
          style={{position:'absolute',top:14,right:14,zIndex:10,
          background:'rgba(0,0,0,0.5)',border:'1px solid rgba(255,255,255,0.25)',borderRadius:20,
          color:'#fff',padding:'6px 14px',cursor:'pointer',fontSize:13,backdropFilter:'blur(6px)'}}/>
      </div>

      {/* ── Navigation (desktop only — mobile uses bottom nav) ── */}
      {!M&&<div style={{position:'sticky',top:0,zIndex:100,background:T.bg,
        borderBottom:'1px solid '+T.border,padding:'10px 16px',
        display:'flex',gap:8,flexWrap:'wrap',alignItems:'center'}}>
        {navBtn('catalogue','&#x1F33F; Plants')}
        {navBtn('map',      '&#x1F5FA; Maps')}
        {navBtn('irrigation','&#x1F4A7; Irrigation')}
        {navBtn('calendar', '&#x1F4C5; Care Schedule')}
        {navBtn('dashboard','&#x1F4CA; Dashboard',attention||'')}
        {navBtn('wishlist', '&#x1F331; Wishlist',wishlist.length||'')}
        <NotificationManager allPlants={allPlants} careLog={careLog}/>
      </div>}

      <div style={{maxWidth:view==='map'?'none':1200,margin:'0 auto',
        padding:view==='map'?(M?'0 8px 100px':'0 16px 40px'):(M?'0 12px 100px':'0 20px 60px')}}>
        {/* ── Catalogue View ── */}
        {view==='catalogue'&&(<>
          {/* Search + Tags */}
          <div style={{position:'sticky',top:M?0:52,zIndex:90,background:T.bg,
            borderBottom:'1px solid '+T.border,marginBottom:16}}>
            {/* Search row */}
            <div style={{display:'flex',gap:8,alignItems:'center',padding:M?'8px 0':'12px 0 8px'}}>
              <input value={search} onChange={e=>setSearch(e.target.value)}
                placeholder="Search plants..." style={{
                  flex:1,padding:M?'10px 14px':'10px 16px',background:T.input,
                  border:'1px solid '+T.border,borderRadius:10,color:T.text,
                  fontSize:14,outline:'none'}}/>
              {!M&&scrolled&&tags.length>0&&(
                <span style={{background:T.accent,color:'#fff',borderRadius:20,
                  padding:'3px 10px',fontSize:12,fontWeight:700,flexShrink:0,whiteSpace:'nowrap'}}>
                  {tags.length} filter{tags.length!==1?'s':''} active
                </span>
              )}
            </div>
            {/* Tag chips:
                Mobile  — single horizontal scroll row, always visible, no wrapping
                Desktop — wrapping rows, auto-collapse on scroll */}
            {M?(
              <div className="chip-row" style={{
                display:'flex',gap:7,overflowX:'auto',paddingBottom:10,
                msOverflowStyle:'none',scrollbarWidth:'none',WebkitOverflowScrolling:'touch'}}>
                {tags.length>0&&(
                  <button onClick={()=>setTags([])} style={{
                    flexShrink:0,padding:'6px 12px',borderRadius:20,whiteSpace:'nowrap',
                    border:'1px solid #ef4444',background:'rgba(239,68,68,0.12)',
                    color:'#ef4444',cursor:'pointer',fontSize:12,fontWeight:700}}>
                    &#x2715; Clear
                  </button>
                )}
                {allTags.map(t=>{
                  const cfg=TAG_C[t]||{},on=tags.includes(t);
                  return <button key={t} onClick={()=>toggleTag(t)} style={{
                    flexShrink:0,padding:'6px 14px',borderRadius:20,whiteSpace:'nowrap',
                    border:'1px solid '+(on?T.accent:T.border),
                    background:on?(cfg.bg||T.accent):(cfg.bg||T.input),
                    color:on?'#fff':(cfg.text||T.sub),
                    cursor:'pointer',fontSize:12,fontWeight:on?700:400,
                  }}>{t}</button>;
                })}
              </div>
            ):(
              <div style={{maxHeight:scrolled?0:300,overflow:'hidden',
                transition:'max-height 0.25s ease',paddingBottom:scrolled?0:10}}>
                <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
                  {allTags.map(t=>{
                    const cfg=TAG_C[t]||{};
                    return <button key={t} onClick={()=>toggleTag(t)} style={{
                      padding:'4px 10px',borderRadius:20,
                      border:'1px solid '+(tags.includes(t)?T.accent:T.border),
                      background:tags.includes(t)?(cfg.bg||T.accent):(cfg.bg||T.tag),
                      color:tags.includes(t)?'#fff':(cfg.text||T.tagText),
                      cursor:'pointer',fontSize:12,fontWeight:tags.includes(t)?600:400,
                    }}>{t}</button>;
                  })}
                </div>
              </div>
            )}
          </div>

          {/* Bulk water button */}
          {attention>0&&(
            <div style={{marginBottom:8,display:'flex',justifyContent:'flex-end'}}>
              <button onClick={()=>setBulkWaterModal(true)} style={{
                padding:'6px 14px',background:'rgba(59,130,246,0.12)',border:'1px solid rgba(59,130,246,0.35)',
                borderRadius:8,color:'#3b82f6',fontSize:12,fontWeight:600,cursor:'pointer',display:'flex',alignItems:'center',gap:6}}>
                &#x1F4A7; Water all overdue ({attention})
              </button>
            </div>
          )}

          {/* Outdoor */}
          {fOutdoor.length>0&&<>{sectionHdr('&#x1F33B; Outdoor Garden',fOutdoor.length)}
            <div key={'out-'+search+tags.join()} className="cards-grid" style={{display:'flex',flexWrap:'wrap',gap:M?8:16,marginBottom:8}}>
              {fOutdoor.map((p,i)=><OutdoorCard key={p.id} plant={p} onSelect={setSelected}
                careLog={careLog} onLog={logCare} onPhotoZoom={setLightboxSrc} animIdx={i} pestLog={pestLog} onPest={setPestModal}/>)}
            </div></>}

          {/* Indoor */}
          {fIndoor.length>0&&<>{sectionHdr('&#x1F3E0; Indoor Plants',fIndoor.length)}
            <div key={'in-'+search+tags.join()} className="cards-grid" style={{display:'flex',flexWrap:'wrap',gap:M?8:16,marginBottom:8}}>
              {fIndoor.map((p,i)=><IndoorCard key={p.id} plant={p} onSelect={setSelected}
                careLog={careLog} onLog={logCare} onPhotoZoom={setLightboxSrc} animIdx={i} pestLog={pestLog} onPest={setPestModal}/>)}
            </div></>}

          {/* Greenhouse */}
          {fHydro.length>0&&<>{sectionHdr('&#x1F9EA; Greenhouse & Hydroponics',fHydro.length)}
            <div key={'hy-'+search+tags.join()} className="cards-grid" style={{display:'flex',flexWrap:'wrap',gap:M?8:16,marginBottom:8}}>
              {fHydro.map((p,i)=><HydroCard key={p.id} plant={p} onSelect={setSelected}
                careLog={careLog} onLog={logCare} onPhotoZoom={setLightboxSrc} animIdx={i} pestLog={pestLog} onPest={setPestModal}/>)}
            </div></>}

          {!fOutdoor.length&&!fIndoor.length&&!fHydro.length&&(
            <div style={{textAlign:'center',padding:60,color:T.sub,fontSize:16}}>
              No plants match your search.
            </div>
          )}
        </>)}

        {/* ── Maps View ── */}
        {view==='map'&&(
          <div style={{paddingTop:mapFull?0:20}}>
            {/* Header row — hidden when full-screen */}
            {!mapFull&&(
              <div style={{display:'flex',alignItems:'center',gap:12,marginBottom:16,flexWrap:'wrap'}}>
                <h2 style={{fontSize:20,fontWeight:700,color:T.text}}>&#x1F5FA; Plant Maps</h2>
                <div style={{display:'flex',gap:6,marginLeft:'auto',flexWrap:'wrap',alignItems:'center'}}>
                  {['indoor','courtyard','garden','greenhouse'].map(k=>(
                    <div key={k} style={{display:'flex',alignItems:'center',gap:0}}>
                      {editingMap===k?(
                        <input autoFocus value={editingName}
                          onChange={e=>setEditingName(e.target.value)}
                          onBlur={()=>saveMapName(k,editingName)}
                          onKeyDown={e=>{
                            if(e.key==='Enter')saveMapName(k,editingName);
                            if(e.key==='Escape')setEditingMap(null);
                          }}
                          style={{padding:'4px 10px',borderRadius:'20px 0 0 20px',border:'1px solid '+T.accent,
                            background:T.input,color:T.text,fontSize:12,outline:'none',width:110}}/>
                      ):(
                        <button onClick={()=>setMapTab(k)} style={{
                          padding:'5px 10px 5px 14px',borderRadius:20,
                          border:'1px solid '+T.border,cursor:'pointer',fontSize:12,
                          background:mapTab===k?T.green:T.input,
                          color:mapTab===k?'#fff':T.text,fontWeight:mapTab===k?700:400,
                          display:'flex',alignItems:'center',gap:5}}>
                          <span dangerouslySetInnerHTML={{__html:MAP_ICONS[k]}}/>
                          {getMapName(k)}
                        </button>
                      )}
                      {editingMap!==k&&(
                        <button onClick={e=>{e.stopPropagation();setEditingMap(k);setEditingName(getMapName(k));}}
                          title="Rename map"
                          style={{padding:'5px 8px',border:'1px solid '+T.border,borderLeft:'none',
                            borderRadius:'0 20px 20px 0',cursor:'pointer',fontSize:11,lineHeight:1,
                            background:mapTab===k?T.green:T.input,
                            color:mapTab===k?'rgba(255,255,255,0.75)':T.sub}}>
                          &#x270F;&#xFE0F;
                        </button>
                      )}
                    </div>
                  ))}
                  {/* Settings */}
                  <button onClick={()=>setShowMapSettings(s=>!s)} title="Customise map grid"
                    style={{padding:'5px 10px',borderRadius:20,border:'1px solid '+(showMapSettings?T.accent:T.border),
                      cursor:'pointer',fontSize:13,background:showMapSettings?'rgba(74,124,63,0.12)':T.input,
                      color:showMapSettings?T.accent:T.sub}}>
                    &#x2699;&#xFE0F;
                  </button>
                  {/* Expand to full screen */}
                  <button onClick={()=>setMapFull(true)} title="Full screen"
                    style={{padding:'5px 10px',borderRadius:20,border:'1px solid '+T.border,
                      cursor:'pointer',fontSize:13,background:T.input,color:T.sub}}>
                    &#x26F6;
                  </button>
                </div>
              </div>
            )}
            {/* Compact bar shown only in full-screen mode */}
            {mapFull&&(
              <div style={{display:'flex',alignItems:'center',gap:6,marginBottom:6,flexWrap:'wrap'}}>
                {['indoor','courtyard','garden','greenhouse'].map(k=>(
                  <button key={k} onClick={()=>setMapTab(k)} style={{
                    padding:'4px 12px',borderRadius:20,border:'1px solid '+T.border,cursor:'pointer',fontSize:11,
                    background:mapTab===k?T.green:T.input,color:mapTab===k?'#fff':T.text,
                    fontWeight:mapTab===k?700:400,display:'flex',alignItems:'center',gap:4}}>
                    <span dangerouslySetInnerHTML={{__html:MAP_ICONS[k]}}/>
                    {getMapName(k)}
                  </button>
                ))}
                <button onClick={()=>setMapFull(false)} title="Exit full screen"
                  style={{marginLeft:'auto',padding:'4px 10px',borderRadius:20,border:'1px solid '+T.border,
                    cursor:'pointer',fontSize:13,background:T.input,color:T.sub}}>
                  &#x2715; Exit
                </button>
              </div>
            )}
            {/* Map settings panel */}
            {showMapSettings&&!mapFull&&(()=>{
              const cfg=getMapCfg(mapTab);
              const def=MAP_SIZE_DEFAULTS[mapTab];
              const isCustom=JSON.stringify(cfg)!==JSON.stringify(def);
              return(
                <div style={{background:T.card,border:'1px solid '+T.border,borderRadius:10,
                  padding:'10px 14px',marginBottom:12,display:'flex',alignItems:'center',
                  gap:16,flexWrap:'wrap'}}>
                  <span style={{fontSize:12,fontWeight:700,color:T.text}}>
                    &#x2699;&#xFE0F; {getMapName(mapTab)}
                  </span>
                  <div style={{display:'flex',alignItems:'center',gap:6}}>
                    <span style={{fontSize:11,color:T.sub}}>Cols</span>
                    <input type="number" min={3} max={30} value={cfg.cols}
                      onChange={e=>updateMapCfg(mapTab,{cols:Math.max(3,Math.min(30,+e.target.value||cfg.cols))})}
                      style={{width:52,padding:'4px 6px',borderRadius:6,border:'1px solid '+T.border,
                        background:T.input,color:T.text,fontSize:12,textAlign:'center',outline:'none'}}/>
                    <span style={{fontSize:11,color:T.sub}}>Rows</span>
                    <input type="number" min={3} max={24} value={cfg.rows}
                      onChange={e=>updateMapCfg(mapTab,{rows:Math.max(3,Math.min(24,+e.target.value||cfg.rows))})}
                      style={{width:52,padding:'4px 6px',borderRadius:6,border:'1px solid '+T.border,
                        background:T.input,color:T.text,fontSize:12,textAlign:'center',outline:'none'}}/>
                  </div>
                  <div style={{display:'flex',alignItems:'center',gap:5}}>
                    <span style={{fontSize:11,color:T.sub}}>Cell</span>
                    {[['XS',48],['S',60],['M',76],['L',92],['XL',112]].map(([lbl,s])=>(
                      <button key={lbl} onClick={()=>updateMapCfg(mapTab,{size:s})}
                        style={{padding:'3px 8px',borderRadius:6,border:'1px solid '+T.border,
                          cursor:'pointer',fontSize:11,
                          background:cfg.size===s?T.accent:T.input,
                          color:cfg.size===s?'#fff':T.text,
                          fontWeight:cfg.size===s?700:400}}>
                        {lbl}
                      </button>
                    ))}
                  </div>
                  <div style={{display:'flex',gap:8,marginLeft:'auto'}}>
                    {isCustom&&<button onClick={()=>resetMapCfg(mapTab)}
                      style={{padding:'3px 10px',borderRadius:20,border:'1px solid '+T.border,
                        cursor:'pointer',fontSize:11,background:T.input,color:T.sub}}>
                      &#x21BA; Reset Size
                    </button>}
                    <button onClick={()=>resetMapLayout(mapTab)}
                      title="Clears saved plant placements, zones and labels for this map, restoring the built-in defaults"
                      style={{padding:'3px 10px',borderRadius:20,border:'1px solid '+T.border,
                        cursor:'pointer',fontSize:11,background:T.input,color:'#ef4444'}}>
                      &#x1F5D1;&#xFE0F; Reset Layout
                    </button>
                  </div>
                </div>
              );
            })()}
            {!mapFull&&<p style={{color:T.sub,fontSize:13,marginBottom:12}}>
              Drag plants onto the grid &bull; Double-click to remove (in &#x1F331; Place mode) &bull; &#x270F;&#xFE0F; rename map
            </p>}
            {mapTab==='garden'&&(()=>{const c=getMapCfg('garden');return<MapGrid storageKey="garden-map" cols={c.cols} rows={c.rows} size={c.size} zones={null} defaultFilter="outdoor" allPlants={allPlants} careLog={careLog} onSelect={setSelected} fullHeight={mapFull}/>;})()}
            {mapTab==='courtyard'&&(()=>{const c=getMapCfg('courtyard');return<MapGrid storageKey="courtyard-map" cols={c.cols} rows={c.rows} size={c.size} zones={COURTYARD_ZONES} defaultFilter="outdoor" defaultPos={COURTYARD_DEFAULT} defaultText={COURTYARD_TEXT} allPlants={allPlants} careLog={careLog} onSelect={setSelected} fullHeight={mapFull}/>;})()}
            {mapTab==='greenhouse'&&(()=>{const c=getMapCfg('greenhouse');return<MapGrid storageKey="greenhouse-map" cols={c.cols} rows={c.rows} size={c.size} zones={GREENHOUSE_ZONES} defaultFilter="hydro" defaultPos={GREENHOUSE_DEFAULT} allPlants={allPlants} careLog={careLog} onSelect={setSelected} fullHeight={mapFull}/>;})()}
            {mapTab==='indoor'&&(()=>{const c=getMapCfg('indoor');return<MapGrid storageKey="indoor-map" cols={c.cols} rows={c.rows} size={c.size} zones={INDOOR_ZONES} defaultFilter="indoor" allPlants={allPlants} careLog={careLog} onSelect={setSelected} fullHeight={mapFull}/>;})()}
          </div>
        )}

        {/* ── Irrigation System View ── */}
        {view==='irrigation'&&(
          <div style={{paddingTop:28}}>
            <IrrigationMap allPlants={allPlants}/>
          </div>
        )}

        {/* ── Care Schedule View ── */}
        {view==='calendar'&&(
          <div style={{paddingTop:28}}>
            <h2 style={{fontSize:20,fontWeight:700,color:T.text,marginBottom:6}}>&#x1F4C5; Care Schedule</h2>
            <p style={{color:T.sub,fontSize:13,marginBottom:24}}>Watering calendar, seasonal tasks, and sowing guide.</p>
            <WateringCalendarView allPlants={allPlants} careLog={careLog}/>
            <SeasonalTasksPanel allPlants={allPlants}/>
            <h3 style={{fontSize:16,fontWeight:700,color:T.text,margin:'0 0 12px'}}>&#x1F331; Sowing Calendar</h3>
            <p style={{color:T.sub,fontSize:13,marginBottom:16}}>When to sow, propagate, or plant out each species across the year.</p>
            <SowingCalendar allPlants={allPlants}/>
          </div>
        )}

        {/* ── Dashboard View ── */}
        {view==='dashboard'&&(
          <div style={{paddingTop:28}}>
            <h2 style={{fontSize:20,fontWeight:700,color:T.text,marginBottom:6}}>&#x1F4CA; Care Dashboard</h2>
            <p style={{color:T.sub,fontSize:13,marginBottom:16}}>Track watering, feeding, repotting, and recent care activity.</p>
            <WeatherWidget/>
            <DashboardView allPlants={allPlants} careLog={careLog} onLog={logCare} onSelect={setSelected}/>
            <BackupRestorePanel/>
          </div>
        )}

        {/* ── Wishlist View ── */}
        {view==='wishlist'&&(
          <WishlistView wishlist={wishlist} onAdd={addWish} onRemove={removeWish}/>
        )}
      </div>

      {/* ── Mobile Bottom Navigation ── */}
      {M&&(
        <div style={{position:'fixed',bottom:0,left:0,right:0,zIndex:200,
          background:T.card,borderTop:'1px solid '+T.border,
          display:'flex',alignItems:'stretch',
          paddingBottom:'env(safe-area-inset-bottom)'}}>
          {[
            ['catalogue','&#x1F33F;','Plants',null],
            ['map','&#x1F5FA;','Maps',null],
            ['irrigation','&#x1F4A7;','Irrigate',null],
            ['calendar','&#x1F4C5;','Schedule',null],
            ['dashboard','&#x1F4CA;','Care',attention||null],
            ['wishlist','&#x1F331;','Wishlist',wishlist.length||null],
          ].map(([k,icon,lbl,badge])=>(
            <button key={k} onClick={()=>setView(k)} style={{
              flex:1,padding:'9px 2px 7px',border:'none',background:'transparent',
              cursor:'pointer',display:'flex',flexDirection:'column',alignItems:'center',gap:1,
              color:view===k?T.accent:T.sub,position:'relative'}}>
              <span style={{fontSize:20,lineHeight:1}} dangerouslySetInnerHTML={{__html:icon}}/>
              <span style={{fontSize:9,fontWeight:view===k?700:400}}>{lbl}</span>
              {badge>0&&(
                <span style={{position:'absolute',top:5,right:'calc(50% - 18px)',background:k==='filter'?T.accent:'#ef4444',
                  color:'#fff',borderRadius:20,padding:'0px 5px',fontSize:9,fontWeight:700,minWidth:16,textAlign:'center'}}>{badge}</span>
              )}
            </button>
          ))}
        </div>
      )}

      {/* ── Overlays ── */}
      {selected&&<DetailPanel plant={selected} onClose={()=>setSelected(null)}
        careLog={careLog} onLog={logCare} onPhotoZoom={setLightboxSrc}
        notes={notes} harvests={harvests} onAddNote={addNote} onAddHarvest={addHarvest}
        careHistory={careHistory} pestLog={pestLog} onPest={setPestModal}/>}
      {lightboxSrc&&<PhotoLightbox src={lightboxSrc} onClose={()=>setLightboxSrc(null)}/>}
      {pestModal&&<PestLogModal plant={pestModal} pestLog={pestLog}
        onLog={logPest} onResolve={resolvePest} onClose={()=>setPestModal(null)}/>}
      {bulkWaterModal&&<BulkWaterModal
        plants={allPlants.filter(p=>getUrgency(p,careLog,'watered').level==='overdue')}
        onConfirm={bulkWater} onClose={()=>setBulkWaterModal(false)}/>}
    </ThemeCtx.Provider>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<Catalogue/>);
